import React from "react";

const projects = [
  {
    title: "Customer Discount Request",
    platform: "Shopware 6",
    domain: "Ecommerce",
    type: "Product",
    description: `A plugin allowing registered users to request a price discount for large quantities of products. Merchants can review, accept, or reject discount proposals.`,
    link: "https://store.shopware.com/en/brand27683468217m/customer-discount-request.html",
  },
  {
    title: "Product Review Synchronization",
    platform: "Shopware 6",
    domain: "Ecommerce",
    type: "Plugin",
    description: `Automates customer review synchronization across multiple shops, ensuring consistent feedback display and improved trust among users.`,
  },
  {
    title: "Category Discount Plugin",
    platform: "Shopware 6",
    domain: "Ecommerce",
    type: "Plugin",
    description: `Allows merchants to configure category-wide discounts, display promotional banners, and adjust pricing dynamically based on set conditions.`,
  },
  {
    title: "TitanPoint Site Optimization",
    platform: "Custom Development",
    domain: "Ecommerce",
    type: "Optimization",
    description: `Optimized site multimedia by converting images to WebP, improving SEO with 'Alt' attributes, and refining CSS for better performance.`,
  },
];

const Projects = () => {
  return (
    <section className="min-h-screen bg-gray-50 py-16 px-6">
      <div className="container mx-auto max-w-6xl">
        <h2 className="text-5xl font-bold text-gray-800 text-center mb-12">My Projects</h2>
        <div className="grid md:grid-cols-2 lg:grid-cols-2 gap-8">
          {projects.map((project, index) => (
            <div
              key={index}
              className="bg-white shadow-lg rounded-xl p-6 border border-gray-200 hover:shadow-2xl transition-all duration-300"
            >
              <h3 className="text-2xl font-semibold text-gray-800 mb-3">{project.title}</h3>
              <p className="text-gray-700 mb-2">
                <strong className="text-gray-900">Platform:</strong> {project.platform} |{" "}
                <strong className="text-gray-900">Domain:</strong> {project.domain} |{" "}
                <strong className="text-gray-900">Type:</strong> {project.type}
              </p>
              <p className="text-gray-600 mb-4 leading-relaxed">{project.description}</p>
              {project.link && (
                <a
                  href={project.link}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="inline-block bg-gradient-to-r from-blue-500 to-purple-600 text-white font-medium py-2 px-5 rounded-lg shadow-md hover:scale-105 transform transition duration-300"
                >
                  View Project
                </a>
              )}
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Projects;
